class TemporaryFile(Generic[AnyStr]):
    """
    An asynchronous temporary file that is automatically created and cleaned up.

    This class provides an asynchronous context manager interface to a temporary file.
    The file is created using Python's standard `tempfile.TemporaryFile` function in a
    background thread, and is wrapped as an asynchronous file using `AsyncFile`.
    """

    _async_file: AsyncFile[AnyStr]

    @overload
    def __init__(
        self: TemporaryFile[bytes],
        mode: "OpenBinaryMode" = ...,
        buffering: int = ...,
        encoding: str | None = ...,
        newline: str | None = ...,
        suffix: str | None = ...,
        prefix: str | None = ...,
        dir: str | None = ...,
        *,
        errors: str | None = ...,
    ): ...
    @overload
    def __init__(
        self: TemporaryFile[str],
        mode: "OpenTextMode",
        buffering: int = ...,
        encoding: str | None = ...,
        newline: str | None = ...,
        suffix: str | None = ...,
        prefix: str | None = ...,
        dir: str | None = ...,
        *,
        errors: str | None = ...,
    ): ...

    def __init__(
        self,
        mode: "OpenTextMode" | "OpenBinaryMode" = "w+b",
        buffering: int = -1,
        encoding: str | None = None,
        newline: str | None = None,
        suffix: str | None = None,
        prefix: str | None = None,
        dir: str | None = None,
        *,
        errors: str | None = None,
    ) -> None:
        """Initialize a TemporaryFile wrapper with the given tempfile parameters."""
        self.mode = mode
        self.buffering = buffering
        self.encoding = encoding
        self.newline = newline
        self.suffix: str | None = suffix
        self.prefix: str | None = prefix
        self.dir: str | None = dir
        self.errors = errors

    async def __aenter__(self) -> AsyncFile[AnyStr]:
        fp = await to_thread.run_sync(
            lambda: tempfile.TemporaryFile(
                self.mode,
                self.buffering,
                self.encoding,
                self.newline,
                self.suffix,
                self.prefix,
                self.dir,
                errors=self.errors,
            )
        )
        self._async_file = AsyncFile(fp)
        return self._async_file

    async def __aexit__(
        self,
        exc_type: type[BaseException] | None,
        exc_value: BaseException | None,
        traceback: TracebackType | None,
    ) -> None:
        await self._async_file.aclose()


class NamedTemporaryFile(Generic[AnyStr]):
    """
    An asynchronous named temporary file that is automatically created and cleaned up.

    This class provides an asynchronous context manager for a temporary file with a
    visible name in the file system. It uses Python's standard
    :func:`~tempfile.NamedTemporaryFile` function and wraps the file object with
    :class:`AsyncFile` for asynchronous operations.
    """

    _async_file: AsyncFile[AnyStr]

    @overload
    def __init__(
        self: NamedTemporaryFile[bytes],
        mode: "OpenBinaryMode" = ...,
        buffering: int = ...,
        encoding: str | None = ...,
        newline: str | None = ...,
        suffix: str | None = ...,
        prefix: str | None = ...,
        dir: str | None = ...,
        *,
        delete: bool = ...,
        errors: str | None = ...,
    ): ...
    @overload
    def __init__(
        self: NamedTemporaryFile[str],
        mode: "OpenTextMode",
        buffering: int = ...,
        encoding: str | None = ...,
        newline: str | None = ...,
        suffix: str | None = ...,
        prefix: str | None = ...,
        dir: str | None = ...,
        *,
        delete: bool = ...,
        errors: str | None = ...,
    ): ...

    def __init__(
        self,
        mode: "OpenTextMode" | "OpenBinaryMode" = "w+b",
        buffering: int = -1,
        encoding: str | None = None,
        newline: str | None = None,
        suffix: str | None = None,
        prefix: str | None = None,
        dir: str | None = None,
        *,
        delete: bool = True,
        errors: str | None = None,
    ) -> None:
        """Initialize a NamedTemporaryFile wrapper with the given tempfile parameters."""
        self.mode = mode
        self.buffering = buffering
        self.encoding = encoding
        self.newline = newline
        self.suffix = suffix
        self.prefix = prefix
        self.dir = dir
        self.delete = delete
        self.errors = errors

    async def __aenter__(self) -> AsyncFile[AnyStr]:
        fp = await to_thread.run_sync(
            lambda: tempfile.NamedTemporaryFile(
                self.mode,
                self.buffering,
                self.encoding,
                self.newline,
                self.suffix,
                self.prefix,
                self.dir,
                delete=self.delete,
                errors=self.errors,
            )
        )
        self._async_file = AsyncFile(fp)
        return self._async_file

    async def __aexit__(
        self,
        exc_type: type[BaseException] | None,
        exc_value: BaseException | None,
        traceback: TracebackType | None,
    ) -> None:
        # Ensure the file is properly closed (and deleted if requested).
        await self._async_file.aclose()


class SpooledTemporaryFile(Generic[AnyStr]):
    """
    An asynchronous spooled temporary file.

    This class creates a temporary file that is kept in memory until it reaches a
    specified maximum size, at which point it will be rolled over to an on-disk file.
    It mirrors the behavior of tempfile.SpooledTemporaryFile but wraps the file in an
    AsyncFile for asynchronous operations.
    """

    _async_file: AsyncFile[AnyStr]

    @overload
    def __init__(
        self: SpooledTemporaryFile[bytes],
        max_size: int = ...,
        mode: "OpenBinaryMode" = ...,
        buffering: int = ...,
        encoding: str | None = ...,
        newline: str | None = ...,
        suffix: str | None = ...,
        prefix: str | None = ...,
        dir: str | None = ...,
        *,
        errors: str | None = ...,
    ) -> None: ...
    @overload
    def __init__(
        self: SpooledTemporaryFile[str],
        max_size: int,
        mode: "OpenTextMode",
        buffering: int = ...,
        encoding: str | None = ...,
        newline: str | None = ...,
        suffix: str | None = ...,
        prefix: str | None = ...,
        dir: str | None = ...,
        *,
        errors: str | None = ...,
    ) -> None: ...

    def __init__(
        self,
        max_size: int = 0,
        mode: "OpenTextMode" | "OpenBinaryMode" = "w+b",
        buffering: int = -1,
        encoding: str | None = None,
        newline: str | None = None,
        suffix: str | None = None,
        prefix: str | None = None,
        dir: str | None = None,
        *,
        errors: str | None = None,
    ) -> None:
        """Initialize a SpooledTemporaryFile wrapper with the given tempfile parameters."""
        self.max_size = max_size
        self.mode = mode
        self.buffering = buffering
        self.encoding = encoding
        self.newline = newline
        self.suffix = suffix
        self.prefix = prefix
        self.dir = dir
        self.errors = errors

    async def __aenter__(self) -> AsyncFile[AnyStr]:
        fp = await to_thread.run_sync(
            lambda: tempfile.SpooledTemporaryFile(
                self.max_size,
                self.mode,
                self.buffering,
                self.encoding,
                self.newline,
                self.suffix,
                self.prefix,
                self.dir,
                errors=self.errors,
            )
        )
        self._async_file = AsyncFile(fp)
        return self._async_file

    async def __aexit__(
        self,
        exc_type: type[BaseException] | None,
        exc_value: BaseException | None,
        traceback: TracebackType | None,
    ) -> None:
        await self._async_file.aclose()


class TemporaryDirectory:
    """
    An asynchronous temporary directory context manager.

    This class creates a temporary directory using tempfile.mkdtemp in a thread and
    removes it upon exiting the context. It provides a simple async interface to work
    with temporary directories when using asynchronous code.
    """

    name: str | None

    def __init__(
        self,
        suffix: str | None = None,
        prefix: str | None = None,
        dir: str | None = None,
    ) -> None:
        """Initialize a TemporaryDirectory wrapper with the given parameters."""
        self.suffix = suffix
        self.prefix = prefix
        self.dir = dir
        self.name = None
        self._closed = False

    async def __aenter__(self) -> str:
        self.name = await to_thread.run_sync(
            lambda: tempfile.mkdtemp(suffix=self.suffix, prefix=self.prefix, dir=self.dir)
        )
        return self.name

    async def __aexit__(
        self,
        exc_type: type[BaseException] | None,
        exc_value: BaseException | None,
        traceback: TracebackType | None,
    ) -> None:
        if self.name is None:
            return
        await to_thread.run_sync(lambda: _rmtree(self.name))
        self._closed = True

    @property
    def closed(self) -> bool:
        """Return True if the temporary directory has been removed/closed."""
        return self._closed


def _rmtree(path: str) -> None:
    # Helper to remove a directory tree without raising on missing files.
    if sys.version_info >= (3, 8):
        # Use os.scandir-based implementation for efficiency; in practice we can
        # rely on shutil.rmtree, but implementing a simple version here keeps
        # dependencies minimal.
        for root, dirs, files in os.walk(path, topdown=False):
            for name in files:
                try:
                    os.unlink(os.path.join(root, name))
                except FileNotFoundError:
                    pass
            for name in dirs:
                try:
                    os.rmdir(os.path.join(root, name))
                except FileNotFoundError:
                    pass
        try:
            os.rmdir(path)
        except FileNotFoundError:
            pass
    else:
        # For older Pythons, fallback to shutil.rmtree
        import shutil

        try:
            shutil.rmtree(path)
        except FileNotFoundError:
            pass


class _TemporaryFileWrapper(Generic[AnyStr]):
    """
    Internal wrapper around a temporary file that exposes an AsyncFile and a name.

    This object is returned by functions that create named temporary files where the
    file object and its filesystem name are both desired.
    """

    _async_file: AsyncFile[AnyStr]

    def __init__(self, fp: Any, name: str | None = None) -> None:
        """Initialize the temporary file wrapper with the underlying file and name."""
        self._async_file = AsyncFile(fp)
        self.name = name

    async def close(self) -> None:
        """Close the underlying async file."""
        await self._async_file.aclose()

    @property
    def closed(self) -> bool:
        """Return True if the underlying file is closed."""
        # AsyncFile exposes a 'closed' attribute on the wrapped file, but ensure safe access.
        try:
            return getattr(self._async_file, "closed", False)
        except Exception:
            return False

    def __getattr__(self, item: str) -> Any:
        # Proxy attribute access to the underlying AsyncFile to allow using file-like APIs.
        return getattr(self._async_file, item)